  TYPE RASTER
  TRANSPARENCY 100
  DUMP true
  HEADER   "plantillas/inicio.html"
  TEMPLATE "plantillas/raster.html"
  FOOTER   "plantillas/fin.html" 
  PROJECTION
	"init=epsg:32718"
  END
  METADATA
	"wms_encoding" "LATIN1"
	"layer_encoding" "LATIN1"
	"wms_group_title" "Escenarios hidrológicos periodo 2011 al 2050 Cuenca del Río Urubamba"
	"queryable" "true"         
	"wms_metadataurl_type" "TC211"
	"wms_title" "Anomalía de la precipitación anual (2011-2020), subcuenca del Medio Urubamba"
	"wms_abstract" "Anomalía de la precipitación anual (2011-2020), subcuenca del Medio Urubamba, modelo MIHR - Escenario A1B - Copyright © Servicio Nacional de Meteorología e Hidrología - SENAMHI, fecha: Junio 2010 :: http://www.senamhi.gob.pe, Publicado por el Programa de Adaptación al Cambio Climático  - PACC Perú 2013 :: http://www.paccperu.org.pe"
