	"wms_include_items" "all"
	"wms_exclude_items" "value_0,red,green,blue"
	"force_imagetype" "jpeg"
  END
  CLASS
	NAME "Modelo MIHR - Escenario A1B"
    EXPRESSION ([pixel] = -99999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME " "
    EXPRESSION ([pixel] = -9999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME "Anomalía de pp (%)"
    EXPRESSION ([pixel] = -999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME "-12.3 - -11.0"
    EXPRESSION ([pixel] >= -12.3 AND [pixel] < -11.0)
    COLOR 243 255 20
  END
  CLASS
	NAME "-11.0 - -10.0"
    EXPRESSION ([pixel] >= -11.0 AND [pixel] < -10.0)
    COLOR 208 240 0
  END
  CLASS
	NAME "-10.0 - -9.0"
    EXPRESSION ([pixel] >= -10.0 AND [pixel] < -9.0)
    COLOR 0 255 0
  END
  CLASS
	NAME "-9.0 - -8.0"
    EXPRESSION ([pixel] >= -9.0 AND [pixel] < -8.0)
    COLOR 44 150 69
  END
  CLASS
	NAME "-8.0 - -7.0"
    EXPRESSION ([pixel] >= -8.0 AND [pixel] < -7.0)
    COLOR 80 196 51
  END
  CLASS
	NAME "-7.0 - -6.0"
    EXPRESSION ([pixel] >= -7.0 AND [pixel] < -6.0)
    COLOR 25 230 168
  END
  CLASS
	NAME "-6.0 - -4.0"
    EXPRESSION ([pixel] >= -6.0 AND [pixel] < -4.0)
    COLOR 0 168 132
  END
  CLASS
	NAME "-4.0 - -2.0"
    EXPRESSION ([pixel] >= -4.0 AND [pixel] < -2.0)
    COLOR 41 248 255
  END
  CLASS
	NAME "-2.0 - 0.0"
    EXPRESSION ([pixel] >= -2.0 AND [pixel] < 0)
    COLOR 0 166 255
  END
  CLASS
	NAME "0.0 - 3.1"
    EXPRESSION ([pixel] >= 0.0 AND [pixel] <= 3.1)
    COLOR 0 0 255
  END
END # Layer